code.imports:
import { tags } from 'decantr/tags';
import { css } from 'decantr/css';
import { Button, Image } from 'decantr/components';

code.example:
function HeroSplit() {
  const { section, div, h1, p, span } = tags;

  return section({ class: css('_flex _items[center] _minh[100vh] _relative _overflow[hidden]') },
    // Breathing gradient orbs (background decorations)
    div({ class: css('_absolute _rounded[50%] _blur[100px] _pointer[none] _z0'), style: 'width:700px;height:700px;top:-15%;left:-15%;background:radial-gradient(circle,rgba(254,68,116,0.22),transparent 65%);animation:orbBreathe1 8s ease-in-out infinite' }),
    div({ class: css('_absolute _rounded[50%] _blur[100px] _pointer[none] _z0'), style: 'width:550px;height:550px;bottom:-10%;right:-10%;background:radial-gradient(circle,rgba(10,243,235,0.16),transparent 65%);animation:orbBreathe2 10s ease-in-out infinite' }),
    // Split layout
    div({ class: css('_flex _items[center] _gap16 _mw[1200px] _mx[auto] _px10 _wfull _relative _z2') },
      div({ class: css('_flex0[35%] _flex _items[center] _justify[center]') },
        Image({ src: '/logo.svg', alt: 'Logo', class: css('_wfull _mw[420px] _block'), style: 'animation:logoFloat 4s ease-in-out infinite' })
      ),
      div({ class: css('_flex1 _text[left]') },
        h1({ class: css('_heading1 _fw800 _lh[1.1] _ls[-0.03em] _mb7') },
          'Design Intelligence', span({ class: css('_fgprimary') }, '.'), ' for AI-Generated UI'
        ),
        p({ class: css('_body _fgmuted/60 _mw[540px] _lh[1.75] _mb10') },
          'A structured schema and design intelligence layer that makes AI assistants generate ',
          span({ class: css('_fgprimary _fw700 _italic') }, 'better, more consistent'),
          ' web applications.'
        ),
        div({ class: css('_flex _gap4 _flexwrap') },
          Button({ variant: 'primary', size: 'lg', class: css('_rounded[100px] _shadow') }, 'Get Started'),
          Button({ variant: 'ghost', size: 'lg', class: css('_rounded[100px] _border') }, 'Learn More')
        )
      )
    )
  );
}

